def grade(sample: dict, item: dict) -> float:
    """Score based on response length using sample access pattern."""
    # Model/agent target: access generated response via item.sample
    response = item.get("sample", {}).get("output_text", "")
    if not response:
        # Fallback to direct item access for dataset evaluation
        response = item.get("response", "")
    if not response:
        return 0.0
    length = len(response)
    if length < 50:
        return 0.2
    elif length > 500:
        return 0.5
    return 1.0

def grade(sample: dict, item: dict) -> float:
